import{_ as l}from"./Menu.179edc93.js";import{u as n}from"./composables.96d18f89.js";import{_ as a}from"./article-recherche-ux-cartographie-des-moyens-de-recherche.02a59ab6.js";import{r as e,a as o,e as u,b as c,f as s,o as d}from"./entry.7b9f66e3.js";const p={class:"banniere"},m=s('<div class="margium-l marge-haute-l"><div class="espacium"><div class="colonnes"><div class="colonne"><h1>La recherche UX</h1><div class="projettitre"></div> 20 octobre 2022 \xB7 2 min </div><div class="colonne"></div></div></div></div>',1),b=s('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p> La recherche UX prend du temps, elle est difficile et souvent on\xE9reuse, mais alors pourquoi fait-on de la recherche utilisateur ?<br> Parce que nous ne savons pas, nous avons des aprioris, sur les besoins, les enjeux, les probl\xE8mes auxquels doit r\xE9pondre la conception. Sans elle, la probabilit\xE9 de d\xE9velopper un produit qui manquerait sa cible et sa pertinence serait \xE9lev\xE9e. Il est plus avantageux d&#39;investir dans la recherche que de faire d&#39;en faire l&#39;\xE9conomie et de d\xE9velopper des produits vains. </p><h2>La recherche quantitative</h2><ul><li><b>Les donn\xE9es analytiques</b> Avec des outils comme Matomo ou Google Analytics, il est possible de comprendre les parcours, la d\xE9mographie, faire ressortir les recherches faites sur le site et suivre les conversions.</li><li><b>Les cartes de chaleurs</b> pour d\xE9busquer visuellement les affordances et les fausses affordances des \xE9l\xE9ments d&#39;une page, les zones les plus cliqu\xE9es sont celles o\xF9 l&#39;utilisateur s&#39;arr\xEAte.</li><li><b>Les questionnaires libres</b> pour recueillir des retours sur des questions pr\xE9cises, ils peuvent se constituer de question ouverte, de <abbr title="Question \xE0 choix multiple">QCM</abbr>, d&#39;\xE9chelles d&#39;\xE9valuations (noter de 1 \xE0 7 le service..) dans l&#39;id\xE9al ces questionnaires doivent \xEAtre courts pour enregistrer le plus de retours possible.</li><li><b>Les \xE9chelles scientifiques</b> les \xE9chelles Attrakdiff, UEQ sont con\xE7ues et reconnues pour fiabilit\xE9. Elles sont souvent mises placer pour \xE9valuer l&#39;\xE9volution de la perception du dispositif avant et apr\xE8s modification.</li><li><b>Les retours utilisateur consign\xE9</b> Les messageries de supports, les avis laiss\xE9s et les \xE9valuations de d\xE9part de service sont une source d&#39;input riche en points douloureux et suggestions d\u2019am\xE9lioration.</li><li><b>L&#39;A/B test</b> s\u2019applique \xE0 \xE9valuer l\u2019efficacit\xE9 de 2 solutions, le serveur r\xE9partit les utilisateurs sur 2 versions diff\xE9rentes et les outils analytiques permettent de comparer les m\xE9triques et les taux de conversion aux objectifs des 2 versions. </li></ul><h2>La recherche qualitative</h2><ul><li><b>Entretien UX</b> a pour objectif de s&#39;entretenir avec les utilisateurs ou les parties prenantes et de recueillir, les points douloureux de leurs exp\xE9riences, leurs besoins et les insights</li><li><b>Groupe Focus</b> r\xE9uni un groupe de personnes qui \xE9changent librement sur plusieurs sujets donn\xE9s. Cette m\xE9thode permet d\u2019analyser les diff\xE9rents points de vue et exp\xE9riences des usagers.</li><li><b>l\u2019enqu\xEAte de terrain</b> consiste \xE0 se rendre le point de vente, ou sur le lieu de travail des usagers pour les rencontrer, \xE9changer avec eux sur leurs motivations, leurs besoins. Cela permet d&#39;\xE9tablir des persona et des cartes d&#39;empathie et de r\xE9colter diff\xE9rents inputs pour la recherche.</li><li><b>Observation de terrain</b> qui consiste \xE0 observer les utilisateurs et leurs usages sans \xEAtre per\xE7u comme enqu\xEAteurs, cela permet de voir l&#39;usage r\xE9el des dispositifs avec moins de biais qu&#39;en test utilisateur, mais aussi moins d&#39;input sur ce que pensent et per\xE7oivent les utilisateurs.</li><li><b>La recherche secondaire</b> c&#39;est l\u2019ensemble des recherches UX d\xE9j\xE0 men\xE9 sur des sujets similaires dont les rapports sont rendus accessibles, ils sont utiles pour faire des pr\xE9conisations ou pour des projets o\xF9 le temps de recherche est limit\xE9</li><li><b>Test utilisateurs</b> R\xE9aliser sur l\u2019existant ou un prototype, ils servent \xE0 r\xE9pondre aux hypoth\xE8ses et aux challenges \xE9mis lors de la conception. On donne un sc\xE9nario et des objectifs aux utilisateurs et on note leurs observations, leurs difficult\xE9s et les interrogent sur certains \xE9l\xE9ments</li><li><b>Benchmark UX</b> contrairement au Benchmark mercatique qui s&#39;appuie sur les services et produits concurrents, le Benchmark UX cherche \xE0 identifier les services qui rencontrent des probl\xE9matiques similaires et analyser les solutions mises en place. Par exemple, un service de vente de couche par abonnement peut prendre en Benchmark les services d&#39;abonnement de caf\xE9. </li></ul><h2>Cartographie des m\xE9thodes de recherche UX</h2><img src="'+a+'" loading="lazy" alt="Cartographie des m\xE9thodes sur les axes besoin/usage et quantitative/qualitative"><h2>Les approches de rendu</h2><p class="sans-espacement">Pour regrouper les recherches et les rendre exploitables par les \xE9quipes et les commanditaires, il y a plusieurs options :</p><ul><li><b>L&#39;atomic Research</b> consiste \xE0 consigner les retours et les insights de la recherche de mani\xE8re uniformis\xE9e et tagu\xE9e de sorte \xE0 constituer une grande base de connaissances o\xF9 il est facile et rapide de faire ressortir les informations sur un sujet donn\xE9.</li><li><b>Les livrables propres</b>, plus traditionnel et professionnel lorsque ces derniers sont demand\xE9s par les commanditaires. La qualit\xE9 graphique, d&#39;explication, est plus longue \xE0 produire et ne se focalise pas sur l&#39;essentiel. Il est recommand\xE9 de standardiser ce type de livrable pour optimiser les temps de projets </li><li><b>Les livrables Lean</b> Le Lean UX, a pour pr\xE9cepte de r\xE9duire les livrables pour se concentrer davantage sur les r\xE9sultats, aller \xE0 l&#39;essentiel pour que la passation entre les \xE9quipes de recherche et de conception soit la plus fluide possible.</li></ul><h2>Les livrables</h2><ul><li><b>L&#39;exp\xE9rience Map</b> c&#39;est la cartographie de l&#39;exp\xE9rience utilisateur, elle permet de retracer le parcours utilisateur du d\xE9but \xE0 la fin, par \xE9tapes dans lesquels sont sp\xE9cifi\xE9es les points douloureux, point positif, les insights, les objectifs, les interactions et les \xE9motions. L&#39;objectif est de donner une vue d&#39;ensemble, de rendre visible une exp\xE9rience et de d\xE9finir les challenges pour les \xE9quipes de conception UX.</li><li><b>L&#39;user journey</b> ne vise pas \xE0 rendre compte de l&#39;usage r\xE9el d&#39;un produit ou d&#39;un service, mais \xE0 donner un parcours utilisateur id\xE9al en identifiant les multiples points de contact.</li><li><b>Les persona</b> sont des personnes fictives repr\xE9sentatives des diff\xE9rents segments d&#39;utilisateurs, on note dans leurs descriptions une d\xE9mographie, leurs besoins, objectifs et point douloureux.</li><li><b>Product design value canva</b> Est un \xE9l\xE9ment important de la vision product, il se compose de 2 parties, la partie utilisateur avec les b\xE9n\xE9fices attendus, les besoins et les points douloureux. D&#39;une autre part la partie proposition de valeur qui r\xE9pond \xE0 ces attentes avec les produits/services propos\xE9s, les b\xE9n\xE9fices d&#39;usages, les r\xE9solutions de probl\xE8mes et des solutions.</li><li><b>Carte d\u2019emphatique</b> est un \xE9l\xE9ment de synth\xE8se visuel d&#39;un persona ou d&#39;un utilisateur, qui se concentre sur les sens : ce que la personne dit et fais, ce qu&#39;elle entend, ce qu&#39;elle pense et ressent, ce qu&#39;elle voit, mais aussi les points douloureux et les points positifs.</li></ul></div></div></article>',1),_={__name:"la-recherche-ux",setup(v){const i=e("La recherche UX - Lucas Lacroix"),r=e("Parce que nous ne savons pas, nous avons des aprioris, sur les besoins, les enjeux, les probl\xE8mes auxquels doit r\xE9pondre la conception. Sans elle, la probabilit\xE9 de d\xE9velopper produit qui manquerait sa cible et sa pertinence serait \xE9lev\xE9e");return n({title:i,meta:[{name:"description",content:r}]}),(h,f)=>{const t=l;return d(),o("div",null,[u("div",p,[c(t),m]),b])}}};export{_ as default};
